// ── Helper: obtener el currículum para el idioma activo ──────
function getCurriculum(langCode) {
  const base = FLASHCARD_CURRICULUM[langCode] || FLASHCARD_CURRICULUM['es'];
  const a1   = typeof FLASHCARD_A1 !== 'undefined' ? (FLASHCARD_A1[langCode] || FLASHCARD_A1['es']) : null;
  if (!a1) return base;
  // Merge A1 groups into the curriculum
  return {
    ...base,
    groups: [...base.groups, ...a1.groups]
  };
}

// ── Helper: obtener N cartas aleatorias de grupos anteriores ─
function getReviewCards(curriculum, currentGroupIndex, n = 4) {
  const allPrev = [];
  for (let i = 0; i < currentGroupIndex; i++) {
    allPrev.push(...curriculum.groups[i].cards);
  }
  // Shuffle y tomar N
  for (let i = allPrev.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [allPrev[i], allPrev[j]] = [allPrev[j], allPrev[i]];
  }
  return allPrev.slice(0, Math.min(n, allPrev.length));
}
